#include <bits/stdc++.h>
using namespace std;
const int mod=1e9;
string s;
int n;
long long dp[303][303][2];
int main(){
	cin>>s;
	n=s.size(),s=" "+s;
	for(int i=1;i<=n;i++)
		dp[i][i][1]=1;
	for(int len=2;len<=n;len++)
		for(int l=1;l+len-1<=n;l++){
			int r=l+len-1;
			for(int k=l+1;k<r;k++)
				dp[l][r][0]+=dp[l][k][1]*(dp[k][r][1]+dp[k][r][0]),dp[l][r][0]%=mod;
			if(s[l]==s[r])
				dp[l][r][1]=dp[l+1][r-1][0]+dp[l+1][r-1][1],dp[l][r][1]%=mod;
		}
	printf("%lld",(dp[1][n][0]+dp[1][n][1])%mod);
	return 0;
}
